use std::sync::{Mutex, RwLock};
use std::thread;
use std::time::Duration;

struct LayerAnalyzer {
    data: Mutex<u32>,
    metadata: RwLock<Vec<String>>,
}

impl LayerAnalyzer {
    fn new() -> Self {
        LayerAnalyzer {
            data: Mutex::new(0),
            metadata: RwLock::new(Vec::new()),
        }
    }

    fn analyze_layer(&self, name: &str, size: u32) {
        println!("Analyzing {}...", name);
        thread::sleep(Duration::from_millis(50));
        {
            let mut data = self.data.lock().unwrap();
            *data += size;
        }
        { 
            let mut meta = self.metadata.write().unwrap();
            meta.push(format!("Processed {} with size {}", name, size));
        }
    }

    fn read_summary(&self) -> u32 {
        println!("Reading final summary...");
        let data = self.data.lock().unwrap();
        *data
    }
}

use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

struct Stats {
    count: i64,
    sum: f64,
}

impl Stats {
    fn new() -> Self {
        Stats { count: 0, sum: 0.0 }
    }

    fn update(&mut self, value: f64) {
        self.count += 1;
        self.sum += value;
    }

    fn get_mean(&self) -> f64 {
        if self.count == 0 {
            0.0
        } else {
            self.sum / (self.count as f64)
        }
    }
}

fn main() {
    let stats = Arc::new(Mutex::new(Stats::new()));
    let mut handles = vec![];

    for i in 0..5 {
        let stats_clone = Arc::clone(&stats);
        let handle = thread::spawn(move || {
            thread::sleep(Duration::from_millis((i * 100) as u64));
            let data_point = (i + 1) as f64 * 10.0;
            println!("Thread {} submitting data point: {}", i, data_point);
            {
                let mut guard = stats_clone.lock().unwrap();
                guard.update(data_point);
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let final_stats = stats.lock().unwrap();
    println!("n--- Streaming Complete ---");
    println!("Total Count: {}", final_stats.count);
    println!("Final Mean: {:.2}", final_stats.get_mean());
}

use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;
use std::time::Duration;
use parking_lot::RwLock;

struct SharedState {
    is_running: AtomicBool,
    status_flags: RwLock<u32>,
}

fn main() {
    let shared = Arc::new(SharedState { 
        is_running: AtomicBool::new(true),
        status_flags: RwLock::new(0xDEADBEEF),
    });

    let reader_shared = Arc::clone(&shared);
    let writer1_shared = Arc::clone(&shared);
    let writer2_shared = Arc::clone(&shared);

    let reader_handle = thread::spawn(move || {
        loop {
            thread::sleep(Duration::from_millis(50));
            if !reader_shared.is_running.load(Ordering::Relaxed) {
                break;
            }
            {
                let flags = reader_shared.status_flags.read();
                println!("Reader: Successfully read status flags: 0x{:X}", *flags);
            }
        }
    });

    let writer1_handle = thread::spawn(move || {
        thread::sleep(Duration::from_millis(10));
        while writer1_shared.is_running.load(Ordering::Relaxed) {
            println!("Writer 1: Attempting to update status flags.");
            { 
                let mut flags = writer1_shared.status_flags.write();
                *flags ^= 0x100;
                println!("Writer 1: Updated flags sequentially.");
            }
            thread::sleep(Duration::from_millis(75));
        }
    });

    let writer2_handle = thread::spawn(move || {
        thread::sleep(Duration::from_millis(20));
        while writer2_shared.is_running.load(Ordering::Relaxed) {
            if !writer2_shared.is_running.load(Ordering::Relaxed) {
                break;
            }
            println!("Writer 2: Attempting a read-modify-write cycle.");
            { 
                let mut flags = writer2_shared.status_flags.write();
                *flags |= 0x200;
                println!("Writer 2: Updated status flags.");
            }
            thread::sleep(Duration::from_millis(150));
        }
    });

    thread::sleep(Duration::from_secs(2));
    shared.is_running.store(false, Ordering::Relaxed);

    let _ = reader_handle.join();
    let _ = writer1_handle.join();
    let _ = writer2_handle.join();
}

use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread::spawn;

struct SharedState {
    data_cache: Vec<i32>,
    is_initialized: AtomicBool,
}

fn main() {
    let state = Arc::new(std::sync::Mutex::new(SharedState {
        data_cache: vec![10, 20, 30],
        is_initialized: AtomicBool::new(false),
    }));

    let state_reader = Arc::clone(&state);
    let reader_handle = spawn(move || {
        std::thread::sleep(std::time::Duration::from_millis(50));
        match std::sync::Mutex::lock(&state_reader) {
            Ok(mut s) => {
                println!("Reader acquired lock and read cache size: {}", s.data_cache.len());
                s.is_initialized.store(true, Ordering::SeqCst);
            }
            Err(e) => eprintln!("Reader failed to acquire lock: {}", e),
        }
    });

    let state_writer = Arc::clone(&state);
    let writer_handle = spawn(move || {
        std::thread::sleep(std::time::Duration::from_millis(10));
        match std::sync::Mutex::lock(&state_writer) {
            Ok(mut s) => {
                s.data_cache.push(40);
                println!("Writer updated cache size to: {}", s.data_cache.len());
            }
            Err(e) => eprintln!("Writer failed to acquire lock: {}", e),
        }
    });

    reader_handle.join().unwrap();
    writer_handle.join().unwrap();

    let final_state = std::sync::Mutex::lock(&state).unwrap();
    println!("Final check: Initialized? {}", final_state.is_initialized.load(Ordering::SeqCst));
}

use std::sync::{Arc, Mutex, RwLock};

struct GameState {
    global_settings: RwLock<String>,
    player_health: Mutex<i32>,
    active_unit_count: Mutex<usize>,
}

impl GameState {
    fn new() -> Arc<Self> {
        Arc::new(GameState {
            global_settings: RwLock::new("Default Map Settings".to_string()),
            player_health: Mutex::new(100),
            active_unit_count: Mutex::new(5),
        })
    }

    fn update_setting(&self, new_value: &str) -> Result<(), String> {
        match self.global_settings.write() {
            Ok(mut settings) => {
                *settings = new_value.to_string();
                println!("Global setting updated successfully.");
                Ok(()) 
            },
            Err(e) => Err(format!("Failed to write global settings: {}", e))
        }
    }

    fn read_setting(&self) -> String {
        match self.global_settings.read() {
            Ok(settings) => settings.clone(),
            Err(e) => { 
                println!("Failed to read global settings: {}", e);
                String::from("Error")
            }
        }
    }

    fn take_damage(&self, amount: i32) -> Result<(), String> {
        match self.player_health.lock() {
            Ok(mut health) => {
                *health = (*health - amount).max(0);
                println!("Player took damage. Current health: {}", *health);
                Ok(())
            },
            Err(e) => Err(format!("Failed to lock player health: {}", e))
        }
    }

    fn spawn_unit(&self) -> Result<(), String> {
        match self.active_unit_count.lock() {
            Ok(mut count) => {
                *count += 1;
                println!("New unit spawned. Total units: {}", *count);
                Ok(())
            },
            Err(e) => Err(format!("Failed to lock unit count: {}", e))
        }
    }
}

fn main() {
    let state = GameState::new();

    let reader_state = state.clone();
    let reader_thread = std::thread::spawn(move || {
        for _ in 0..2 {
            std::thread::sleep(std::time::Duration::from_millis(100));
            println!("Reader Thread: Current map state is {}", reader_state.read_setting());
        }
    });

    let writer_state = state.clone();
    let writer_thread = std::thread::spawn(move || {
        std::thread::sleep(std::time::Duration::from_millis(50));
        writer_state.update_setting("Forest Overworld Beta")
            .expect("Setup failed to update setting");
    });

    let action_state = state.clone();
    let action_thread = std::thread::spawn(move || {
        std::thread::sleep(std::time::Duration::from_millis(150));
        action_state.take_damage(20).unwrap();
        action_state.spawn_unit().unwrap();
    });

    writer_thread.join().unwrap();
    reader_thread.join().unwrap();
    action_thread.join().unwrap();
}
